	events <- agentlib.ServiceEvent{
		Type: "tool_call",
		Time: start.Add(serviceNoopCompactionWallClockLimit),
		Data: json.RawMessage(`{"id":"call-1","name":"read","input":{"path":"README.md"}}`),
