func noopCompactionServiceEvent(ts time.Time) agentlib.ServiceEvent {
	return agentlib.ServiceEvent{

		Tokens:                      tokens,
		CostUSD:                     costUSD,
		ExitCode:                    exitCode,
		Error:                       agentErrMsg,
		ExecutionDir:                artifacts.DirRel,
		PromptFile:                  artifacts.PromptRel,
		ManifestFile:                artifacts.ManifestRel,
		ResultFile:                  artifacts.ResultRel,
		UsageFile:                   usageFileRel,
		StartedAt:                   startedAt,
		FinishedAt:                  finishedAt,
